// Apply translations for legal pages
function applyLegalTranslations(page, lang) {
  var sections = [LEGAL_T.footer[lang], LEGAL_T[page] && LEGAL_T[page][lang]];
  sections.forEach(function(t) {
    if (!t) return;
    document.querySelectorAll('[data-i18n]').forEach(function(el) {
      var key = el.getAttribute('data-i18n');
      if (t[key]) el.innerHTML = t[key];
    });
  });
  document.documentElement.lang = lang;
}

// Hook into language selector — pages set window.LEGAL_PAGE_TYPE before loading this script
window.applyLanguage = function(lang) {
  var pageType = window.LEGAL_PAGE_TYPE || 'privacy';
  applyLegalTranslations(pageType, lang);
};
